const MAX_LEN = 3600;
const raw = String($json.result ?? '').trim();

function filterGarbage(text) {
  return text
    .replace(/[\u4e00-\u9fff\u3400-\u4dbf\u3000-\u303f\uf900-\ufaff]/g, '')
    .replace(/[\u0400-\u04ff\u0500-\u052f]/g, '')
    .replace(/[\u0600-\u06ff\u0750-\u077f]/g, '')
    .replace(/[\uff00-\uffef\u3040-\u30ff]/g, '')
    .replace(/[^\x00-\x7F\u00C0-\u024F\u00A0-\u00FF\n]/g, '')
    .trim();
}

function cleanMarkdown(text) {
  return String(text)
    .replace(/```[\s\S]*?```/g, '')
    .replace(/`([^`]+)`/g, '$1')
    .replace(/\[([^\]]+)\]\(([^)]+)\)/g, '$1')
    .replace(/\*\*(.*?)\*\*/g, '$1')
    .replace(/\*(.*?)\*/g, '$1')
    .replace(/__(.*?)__/g, '$1')
    .replace(/_(.*?)_/g, '$1')
    .replace(/_/g, '')
    .replace(/~~(.*?)~~/g, '$1')
    .replace(/^[ \t]*#{1,6}[ \t]*/gm, '')
    .replace(/^[ \t]*>[ \t]?/gm, '')
    .replace(/^[ \t]*[-*][ \t]+/gm, '• ')
    .replace(/^[ \t]*\d+\.[ \t]+/gm, '• ')
    .replace(/^[ \t]*([-*_]){3,}[ \t]*$/gm, '')
    .replace(/\r\n/g, '\n')
    .replace(/\n{3,}/g, '\n\n')
    .trim();
}

function splitText(text, maxLen) {
  if (!text) return ['(sin respuesta)'];
  if (text.length <= maxLen) return [text];
  const chunks = [];
  let remaining = text;
  while (remaining.length > maxLen) {
    let cut = remaining.lastIndexOf('\n\n', maxLen);
    if (cut < Math.floor(maxLen * 0.6)) cut = remaining.lastIndexOf('\n', maxLen);
    if (cut < Math.floor(maxLen * 0.6)) { cut = remaining.lastIndexOf('. ', maxLen); if (cut !== -1) cut += 1; }
    if (cut < Math.floor(maxLen * 0.6)) cut = remaining.lastIndexOf(' ', maxLen);
    if (cut < Math.floor(maxLen * 0.4)) cut = maxLen;
    const part = remaining.slice(0, cut).trim();
    if (part) chunks.push(part);
    remaining = remaining.slice(cut).trim();
  }
  if (remaining) chunks.push(remaining);
  return chunks.length ? chunks : ['(sin respuesta)'];
}

const filtered = filterGarbage(raw);
const cleaned = cleanMarkdown(filtered);
const parts = splitText(cleaned, MAX_LEN);

return parts.map((part, i) => ({
  json: {
    text: part,
    fragmentIndex: i + 1,
    fragmentTotal: parts.length
  }
}));

